upstreamCalls.query:
query PaymentTermsHydrate($id: ID!) {
    paymentTerms: node(id: $id) {
      ... on PaymentTerms {
        id
        due
        overdue
        dueInDays
        paymentTermsName
        paymentTermsType
        translatedName
        order {
          id
          name
          email
          closed
          closedAt
          cancelledAt
          displayFinancialStatus
          totalOutstandingSet {
            shopMoney { amount currencyCode }
            presentmentMoney { amount currencyCode }
          }
          currentTotalPriceSet {
            shopMoney { amount currencyCode }
            presentmentMoney { amount currencyCode }
          }
          totalPriceSet {
            shopMoney { amount currencyCode }
            presentmentMoney { amount currencyCode }
          }
          lineItems(first: 1) {
            nodes {
              sellingPlan {
                name
              }
            }
          }
        }
        draftOrder {
          id
          name
          status
          completedAt
          subtotalPriceSet {
            shopMoney { amount currencyCode }
            presentmentMoney { amount currencyCode }
          }
          totalPriceSet {
            shopMoney { amount currencyCode }
            presentmentMoney { amount currencyCode }
          }
        }
        paymentSchedules(first: 10) {
          nodes {
            id
            dueAt
            issuedAt
            completedAt
            due
            amount { amount currencyCode }
            balanceDue { amount currencyCode }
            totalBalance { amount currencyCode }
          }
        }
      }
    }
  }

